THOUGHT: The crash shows a shufflevector using a value from an insertelement that is placed after the shuffle, causing a dominance violation. My earlier change set the builder’s insert point after creating the insertelement, but if the shuffle is emitted before the insertelement in the current builder sequence, dominance still breaks. A robust fix is to move the newly created insertelement (or vector_insert intrinsic) to before the current IRBuilder insertion point, ensuring it dominates any instructions subsequently created. I will update the CreateInsertElement helper to move InsElt before the current insertion point right after it is created.

```bash
perl -0777 -pe 's/InsElt = II;
\s*if \(InsElt\)
\s*Builder\.SetInsertPoint\(II->getParent\(\), std::next\(II->getIterator\(\)\)\);/InsElt = II;
if (InsElt) {
  if (auto IP = Builder.GetInsertPoint(); IP != II->getIterator())
    II->moveBefore(&*IP);
}/s' -i llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp && perl -0777 -pe 's/InsElt = dyn_cast<InsertElementInst>\(Vec\);
\s*if \(!InsElt\)
\s*  return Vec;
\s*if \(InsElt\)
\s*  Builder\.SetInsertPoint\(InsElt->getParent\(\), std::next\(InsElt->getIterator\(\)\)\);/InsElt = dyn_cast<InsertElementInst>(Vec);
if (!InsElt)
  return Vec;
{
  auto IP = Builder.GetInsertPoint();
  if (IP != InsElt->getIterator())
    InsElt->moveBefore(&*IP);
}/s' -i llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp && sed -n '16080,16140p' llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp && submit-patch || true
