THOUGHT: The dominance error persists likely because insertelement is created in a block that doesn't dominate shufflevector creation. To ensure dominance robustly without analysis, I will move any newly created insertelement/vector_insert to the function entry block start if it is created in a different block than the current IRBuilder insertion block. This guarantees it dominates all later instructions.

```bash
perl -0777 -pe 's/InsElt = II;
if \(InsElt\) \{
  if \(auto IP = Builder\.GetInsertPoint\(\); IP != II->getIterator\(\)\)
    II->moveBefore\(&\*IP\);
}/InsElt = II;
if (InsElt) {
  auto *IPBB = Builder.GetInsertBlock();
  if (IPBB && II->getParent() != IPBB) {
    Function *F = IPBB->getParent();
    II->moveBefore(&*F->getEntryBlock().begin());
  } else if (auto IP = Builder.GetInsertPoint(); IP != II->getIterator()) {
    II->moveBefore(&*IP);
  }
}/s' -i llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp && perl -0777 -pe 's/InsElt = dyn_cast<InsertElementInst>\(Vec\);
if \(!InsElt\)
  return Vec;
\{
  auto IP = Builder\.GetInsertPoint\(\);
  if \(IP != InsElt->getIterator\(\)\)
    InsElt->moveBefore\(&\*IP\);
\}/InsElt = dyn_cast<InsertElementInst>(Vec);
if (!InsElt)
  return Vec;
{
  auto *IPBB = Builder.GetInsertBlock();
  if (IPBB && InsElt->getParent() != IPBB) {
    Function *F = IPBB->getParent();
    InsElt->moveBefore(&*F->getEntryBlock().begin());
  } else {
    auto IP = Builder.GetInsertPoint();
    if (IP != InsElt->getIterator())
      InsElt->moveBefore(&*IP);
  }
}
